import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("returns 5G processing fee for an empty item list");
    it.todo("returns base premium plus first insurance surcharge plus processing fee for a single sword");
    it.todo("returns correct base premium for each main item type (amulet, staff, potion)");
    it.todo("applies 50% cursed surcharge to the affected item's base premium only");
    it.todo("applies 30% high-enchantment surcharge to items with enchantment level >= 5");
    it.todo("applies 20% loyalty discount to the policy base premium for customers with >= 2 years");
    it.todo("applies 15% follow-up contract discount to the policy base premium on subsequent quotes");
    it.todo("charges 25G base premium per component (rune or moonstone)");
    it.todo("applies block pricing of 60G for exactly 3 alike components");
  });

  describe("claim", () => {
    it.todo("subtracts 100G deductible from damage amount for a standard item");
    it.todo("reimburses 50% of damage for items with enchantment level >= 8, then subtracts deductible");
    it.todo("fully reimburses damage to dragon-material items, then subtracts deductible");
    it.todo("caps total payout at twice the policy insurance sum");
  });
});

