const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const quote = (customer: unknown, items: unknown[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const item = items[0] as { type: string };
  const base = BASE_PREMIUM[item.type];
  return base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
