const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const quote = (customer: unknown, items: unknown[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const item = items[0] as { type: string; cursed: boolean; enchantment: number };
  const base = BASE_PREMIUM[item.type];
  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
  const enchantSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
  return base + cursedSurcharge + enchantSurcharge + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

