  const enchantSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
  const followUpDiscount = previousContracts > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
  return Math.ceil(base + cursedSurcharge + enchantSurcharge + base * FIRST_INSURANCE_RATE - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

